<template>
  <div class="navigation-container" :class="{ 'dark-theme': currentTheme === 'dark' }">
  
    <SideNavigation 
      :is-dark-theme="currentTheme === 'dark'"
      :isCollapsed="isSidebarCollapsed"
      :isMobileMenuVisible="isMobileMenuVisible"
      @category-selected="scrollToCategory"
      @sub-category-selected="scrollToSubCategory"
      @clear-top-search="clearTopSearch"
      @update:isCollapsed="isSidebarCollapsed = $event"
      @update:isMobileMenuVisible="isMobileMenuVisible = $event"
    />
    
    <div 
      class="main-content" 
      ref="scrollContainer"
      :class="{ 'menu-visible': isMenuVisible, 'dark-theme': currentTheme === 'dark' }" 
      :style="{ 'margin-left': isSidebarCollapsed ? '0px' : '280px' }"
    >
      <NavigationHeader
        ref="navHeader"
        class="navigation-header"
        :active-index="activeIndex"
        :current-theme="currentTheme"
        @show-donate="donateDialogVisible = true"
        @toggle-theme="toggleTheme"
        @select="handleSelect"
        @search-input="searchQuery = $event"
        @toggle-mobile-menu="toggleSidebar"
      />

 
      
      <NavigationLinks
        ref="navLinks"
        :categories="categories"
        :current-theme="currentTheme"
        :search-query="searchQuery"
        :collapsed-categories="collapsedCategories"
        :target-category="selectedCategory"
        @toggle-category="toggleCategory"
      />

      <NavigationFooter 
        ref="footer"
        :current-theme="currentTheme"
        @show-donate="donateDialogVisible = true"
      />

      <DonateDialog v-model="donateDialogVisible" :current-theme="currentTheme" />


      <div class="floating-tools">
        
        <transition name="fade">
          <div 
            v-show="showBackToTop" 
            class="tool-btn" 
            :class="{ 'dark-theme': currentTheme === 'dark' }"
            @click="scrollToTop"
            title="返回顶部"
          >
            <svg viewBox="0 0 1024 1024" width="24" height="24" fill="currentColor">
              <path d="M512 320L192 640h640z" />
            </svg>
          </div>
        </transition>

        <transition name="fade">
          <div 
            v-show="showGoToBottom" 
            class="tool-btn" 
            :class="{ 'dark-theme': currentTheme === 'dark' }"
            @click="scrollToBottom"
            title="前往底部"
          >
            <svg viewBox="0 0 1024 1024" width="24" height="24" fill="currentColor">
              <path d="M512 704L832 384H192z" />
            </svg>
          </div>
        </transition>

      </div>

    </div>
  </div>
</template>

<script>
import { navData } from "../nav-data.js"
import NavigationHeader from './NavigationHeader.vue'
import NavigationLinks from './NavigationLinks.vue'
import NavigationFooter from './NavigationFooter.vue'
import SideNavigation from './SideNavigation.vue'
import DonateDialog from './DonateDialog.vue'



export default {
  name: 'MainNavigation',
  components: {
    NavigationHeader,
    DonateDialog,
    NavigationLinks,
    NavigationFooter,
    SideNavigation,
   
  },

  data() {
    return {
      activeIndex: 'home',
      isMenuVisible: false,
      donateDialogVisible: false,
      
      isSidebarCollapsed: false,
    isMobileMenuVisible: false,
      currentTheme: localStorage.getItem('theme') || 'light',
      searchQuery: '',
      selectedSearchEngine: localStorage.getItem('defaultSearch') || 'google',
      searchEngines: [
        { label: 'Google', value: 'google', url: 'https://www.google.com/search?q=%s', icon: 'ChromeFilled' },
        { label: 'Bing', value: 'bing', url: 'https://www.bing.com/search?q=%s', icon: 'Search' },
        { label: 'Baidu', value: 'baidu', url: 'https://www.baidu.com/s?wd=%s', icon: 'Search' },
        { label: 'GitHub', value: 'github', url: 'https://github.com/search?q=%s', icon: 'Search' },
      ],
      selectedCategory: '',
      collapsedCategories: [],
      categories: navData,
      // 按钮显示状态
      showBackToTop: false, 
      showGoToBottom: true, // 默认显示底部按钮
      scrollTimer: null, // 滚动节流定时器
    }
  },
  methods: {
    handleSelect(key) {
      this.activeIndex = key
    },
    
    scrollToCategory(categoryName) {
      // 清空站内搜索，确保分类可以正常显示
      if (this.$refs.navLinks) {
        this.$refs.navLinks.clearSearch();
      }
      this.selectedCategory = categoryName;
      const categoryElement = document.querySelector(`[data-category="${categoryName}"]`);
      const container = this.$refs.scrollContainer;
      
      if (categoryElement && container) {
        const elementTop = categoryElement.getBoundingClientRect().top;
        const containerTop = container.getBoundingClientRect().top;
        const currentScroll = container.scrollTop;
        const headerOffset = 80;

        const targetPosition = elementTop - containerTop + currentScroll - headerOffset;

        container.scrollTo({
          top: targetPosition,
          behavior: "auto"
        });
      }
    },
    
    // 滚动到子分类
    scrollToSubCategory({ categoryName }) {
      // 先滚动到父分类
      this.scrollToCategory(categoryName);
      // 展开该分类
      this.$nextTick(() => {
        if (this.$refs.navLinks) {
          this.$refs.navLinks.expandCategory(categoryName);
        }
      });
    },
    
    toggleTheme() {
      this.currentTheme = this.currentTheme === 'light' ? 'dark' : 'light';
      localStorage.setItem('theme', this.currentTheme);
      document.body.classList.toggle('dark', this.currentTheme === 'dark');
      document.documentElement.classList.toggle('dark', this.currentTheme === 'dark');
    },

    clearTopSearch() {
      if (this.$refs.navHeader) {
        this.$refs.navHeader.clearSearch();
      }
    },
    
    toggleCategory(categoryName) {
      const index = this.collapsedCategories.indexOf(categoryName);
      if (index > -1) {
        this.collapsedCategories.splice(index, 1);
      } else {
        this.collapsedCategories.push(categoryName);
      }
    },

    // 滚动监听：同时控制两个按钮的显示（添加节流优化）
    handleScroll() {
      // 节流：如果已有定时器在等待，直接返回
      if (this.scrollTimer) return;
      
      this.scrollTimer = setTimeout(() => {
        this.scrollTimer = null; // 清除定时器
        
        const container = this.$refs.scrollContainer;
        if (container) {
          const scrollTop = container.scrollTop;
          const scrollHeight = container.scrollHeight;
          const clientHeight = container.clientHeight;

          // 超过 300px 显示返回顶部
          this.showBackToTop = scrollTop > 300;

          // 如果距离底部小于 50px，隐藏前往底部按钮
          this.showGoToBottom = scrollTop + clientHeight < scrollHeight - 50;
        }
      }, 100); // 100ms 节流
    },

    // 返回顶部
    scrollToTop() {
      const container = this.$refs.scrollContainer;
      if (container) {
        container.scrollTo({ top: 0, behavior: 'auto' });
      }
    },
    
    toggleSidebar() {
      const isMobile = window.innerWidth <= 768;
      if (isMobile) {
        this.isMobileMenuVisible = !this.isMobileMenuVisible;
      } else {
        this.isSidebarCollapsed = !this.isSidebarCollapsed;
      }
    },

    // 【新增】前往底部
    scrollToBottom() {
      const container = this.$refs.scrollContainer;
      if (container) {
        container.scrollTo({ 
          top: container.scrollHeight, 
          behavior: 'auto' 
        });
      }
    }
  },

  mounted() {
    if (this.currentTheme === 'dark') {
      document.body.classList.add('dark');
      document.documentElement.classList.add('dark');
    } else {
      document.body.classList.remove('dark');
      document.documentElement.classList.remove('dark');
    }
    
    window.addEventListener('error', (e) => {
      if (e.message === 'ResizeObserver loop completed with undelayed notifications.') {
        e.stopImmediatePropagation();
      }
    });

    this.$nextTick(() => {
      if (this.$refs.scrollContainer) {
        this.$refs.scrollContainer.addEventListener('scroll', this.handleScroll);
        // 初始化一次状态
        this.handleScroll();
      }
    });
  },

  beforeUnmount() {
    if (this.$refs.scrollContainer) {
      this.$refs.scrollContainer.removeEventListener('scroll', this.handleScroll);
    }
    if (this.scrollTimer) clearTimeout(this.scrollTimer);
  }
}
</script>

